  "function walletCapContract() view returns (address)",
  "function depositProofToMinted(bytes32 proof) view returns (uint256)",
  "function mint(address to, uint256 amount, bytes32 depositProof)",
  "function burn(address from, uint256 amount)",
  "function auditFreeze()",
  "function auditUnfreeze()",
  "function setWalletCapContract(address cap)",
  "event GoldMinted(address indexed to, uint256 amount, bytes32 indexed depositProof, uint256 gramsInReserve)",
  "event GoldBurned(address indexed from, uint256 amount, uint256 gramsInReserve)",
